import React, { useState } from "react";

function AITrainer() {
  const [issue, setIssue] = useState("");
  const [result, setResult] = useState("");

  function getAdvice() {
    let advice = "";

    if (issue === "Stress") advice = "Practice meditation and deep breathing daily.";
    else if (issue === "Back Pain") advice = "Do light stretching and avoid long sitting.";
    else if (issue === "Knee Pain") advice = "Try leg stretches and avoid high-impact exercises.";
    else if (issue === "Obesity") advice = "Do cardio regularly and maintain a calorie-controlled diet.";
    else if (issue === "Sleep Problem") advice = "Do relaxation exercises and avoid screen time before sleep.";
    else advice = "Maintain regular workouts and a healthy diet.";

    setResult(advice);
  }

  return (
    <div className="card">
      <h3>AI Fitness Trainer</h3>

      <select value={issue} onChange={(e) => setIssue(e.target.value)}>
        <option value="">Select Issue</option>
        <option>Stress</option>
        <option>Back Pain</option>
        <option>Knee Pain</option>
        <option>Obesity</option>
        <option>Sleep Problem</option>
      </select>

      <button onClick={getAdvice}>Get AI Advice</button>

      {result && <div className="advice-box">{result}</div>}
    </div>
  );
}

export default AITrainer;
